        this.clock = new THREE.Clock();
        this.keys = {};
        this.mouse = { x: 0, y: 0 };
        this.isLocked = false;

        this.initPhysics().then(() => {
            this.initLights();
            this.initPlayer();
            this.initEnvironment();
            this.setupEvents();
            this.animate();
        });
    }

    async initPhysics() {
        await RAPIER.init();
        this.world = new RAPIER.World({ x: 0.0, y: -9.81, z: 0.0 });
    }

    initLights() {
        const ambient = new THREE.AmbientLight(0xffffff, 0.6);
        this.scene.add(ambient);

        const sun = new THREE.DirectionalLight(0xffffff, 1);
        sun.position.set(10, 20, 10);
        sun.castShadow = true;
        this.scene.add(sun);
    }

    initPlayer() {
        // Player Physics Body (Capsule)
        const radius = 0.5;
        const height = 1.0;
        const rigidBodyDesc = RAPIER.RigidBodyDesc.dynamic()
            .setTranslation(0, 5, 0)
            .setCanSleep(false)
            .lockRotations();
        this.playerBody = this.world.createRigidBody(rigidBodyDesc);

        const colliderDesc = RAPIER.ColliderDesc.capsule(height / 2, radius);
        this.world.createCollider(colliderDesc, this.playerBody);

        this.playerRotation = new THREE.Euler(0, 0, 0, 'YXZ');
        this.camera.position.set(0, 0.6, 0); // Camera at eye level
    }

    initEnvironment() {
        // Simple Floor
        const floorGeo = new THREE.PlaneGeometry(100, 100);
        const floorMat = new THREE.MeshStandardMaterial({ color: 0x444444 });
        const floor = new THREE.Mesh(floorGeo, floorMat);
        floor.rotation.x = -Math.PI / 2;
        floor.receiveShadow = true;
        this.scene.add(floor);

        // Physics for Floor
        const groundColliderDesc = RAPIER.ColliderDesc.cuboid(50, 0.1, 50);
        this.world.createCollider(groundColliderDesc);

        // Add some obstacles/covers
        for (let i = 0; i < 10; i++) {
            const size = 1 + Math.random() * 2;
            const boxGeo = new THREE.BoxGeometry(size, size, size);
            const boxMat = new THREE.MeshStandardMaterial({ color: 0x888888 });
            const box = new THREE.Mesh(boxGeo, boxMat);

            const x = (Math.random() - 0.5) * 40;
            const z = (Math.random() - 0.5) * 40;
            const y = size / 2;

            box.position.set(x, y, z);
            box.castShadow = true;
            box.receiveShadow = true;
            this.scene.add(box);

            const colliderDesc = RAPIER.ColliderDesc.cuboid(size / 2, size / 2, size / 2)
                .setTranslation(x, y, z);
            this.world.createCollider(colliderDesc);
        }
    }

    setupEvents() {
        window.addEventListener('keydown', (e) => this.keys[e.code] = true);
        window.addEventListener('keyup', (e) => this.keys[e.code] = false);

        const overlay = document.getElementById('overlay');
        overlay.addEventListener('click', () => {
            this.renderer.domElement.requestPointerLock();
        });

        document.addEventListener('pointerlockchange', () => {
            this.isLocked = document.pointerLockElement === this.renderer.domElement;
            overlay.style.display = this.isLocked ? 'none' : 'block';
        });

        window.addEventListener('mousemove', (e) => {
            if (!this.isLocked) return;

            const sensitivity = 0.002;
            this.playerRotation.y -= e.movementX * sensitivity;
            this.playerRotation.x -= e.movementY * sensitivity;
            this.playerRotation.x = Math.max(-Math.PI / 2, Math.min(Math.PI / 2, this.playerRotation.x));
        });

        window.addEventListener('resize', () => {
            this.camera.aspect = window.innerWidth / window.innerHeight;
            this.camera.updateProjectionMatrix();
            this.renderer.setSize(window.innerWidth, window.innerHeight);
        });
    }

    updatePlayer(delta) {
        if (!this.isLocked) return;

        const speed = 10;
        const velocity = { x: 0, y: this.playerBody.linvel().y, z: 0 };

        const forward = new THREE.Vector3(0, 0, -1).applyQuaternion(new THREE.Quaternion().setFromEuler(new THREE.Euler(0, this.playerRotation.y, 0)));
        const right = new THREE.Vector3(1, 0, 0).applyQuaternion(new THREE.Quaternion().setFromEuler(new THREE.Euler(0, this.playerRotation.y, 0)));

        if (this.keys['KeyW']) {
            velocity.x += forward.x * speed;
            velocity.z += forward.z * speed;
        }
        if (this.keys['KeyS']) {
            velocity.x -= forward.x * speed;
            velocity.z -= forward.z * speed;
        }
        if (this.keys['KeyA']) {
            velocity.x -= right.x * speed;
            velocity.z -= right.z * speed;
        }
        if (this.keys['KeyD']) {
            velocity.x += right.x * speed;
            velocity.z += right.z * speed;
        }

        if (this.keys['Space'] && Math.abs(this.playerBody.linvel().y) < 0.1) {
            velocity.y = 5;
        }

        this.playerBody.setLinvel(velocity, true);

        // Sync Camera
        const pos = this.playerBody.translation();
        this.camera.position.set(pos.x, pos.y + 0.6, pos.z);
        this.camera.quaternion.setFromEuler(this.playerRotation);
    }

    animate() {
        requestAnimationFrame(() => this.animate());
        const delta = this.clock.getDelta();

        this.world.step();
        this.updatePlayer(delta);

        this.renderer.render(this.scene, this.camera);
    }
}

