import * as THREE from 'three';
import RAPIER from '@dimforge/rapier3d-compat';

export class MapManager {
    constructor(scene, world) {
        this.scene = scene;
        this.world = world;
        this.meshes = [];
        this.colliders = [];
        this.currentTheme = 'URBAN';

        this.themes = {
            URBAN: { floor: 0x333333, accent: 0x555555, obstacle: 0x777777 },
            SCIFI: { floor: 0x000511, accent: 0x00ffff, obstacle: 0x112244 },
            DESERT: { floor: 0xd2b48c, accent: 0x8b4513, obstacle: 0xa0522d }
        };
    }

    clear() {
        this.meshes.forEach(m => this.scene.remove(m));
        this.colliders.forEach(c => this.world.removeCollider(c));
        this.meshes = [];
        this.colliders = [];
    }

    createBox(w, h, d, x, y, z, color) {
        const geo = new THREE.BoxGeometry(w, h, d);
        const mat = new THREE.MeshStandardMaterial({ color });
        const mesh = new THREE.Mesh(geo, mat);
        mesh.position.set(x, y, z);
        mesh.castShadow = true;
        mesh.receiveShadow = true;
        this.scene.add(mesh);
        this.meshes.push(mesh);

        const desc = RAPIER.ColliderDesc.cuboid(w / 2, h / 2, d / 2).setTranslation(x, y, z);
        const collider = this.world.createCollider(desc);
        this.colliders.push(collider);
        return mesh;
    }

    createRamp(w, h, d, x, y, z, rotZ, color) {
        const mesh = this.createBox(w, h, d, x, y, z, color);
        mesh.rotation.z = rotZ;

        // Remove the box collider and create a rotated one
        this.world.removeCollider(this.colliders.pop());
        const desc = RAPIER.ColliderDesc.cuboid(w / 2, h / 2, d / 2)
            .setTranslation(x, y, z)
            .setRotation(new THREE.Quaternion().setFromEuler(new THREE.Euler(0, 0, rotZ)));
        const collider = this.world.createCollider(desc);
        this.colliders.push(collider);
    }

    loadMap(themeName) {
        this.clear();
        this.currentTheme = themeName;
        const theme = this.themes[themeName];

        // Floor
        this.createBox(100, 0.2, 100, 0, -0.1, 0, theme.floor);

        if (themeName === 'URBAN') {
            this.buildUrban(theme);
        } else if (themeName === 'SCIFI') {
            this.buildSciFi(theme);
        } else if (themeName === 'DESERT') {
            this.buildDesert(theme);
        }
    }

    buildUrban(theme) {
        // Concrete barriers and containers
        for(let i=0; i<15; i++) {
            const x = (Math.random()-0.5)*60;
            const z = (Math.random()-0.5)*60;
            this.createBox(2, 1, 4, x, 0.5, z, theme.obstacle);
        }
        // Ramps
        this.createRamp(10, 0.5, 5, 10, 1.5, 0, -0.3, theme.accent);
        this.createBox(5, 3, 5, 18, 1.5, 0, theme.obstacle);
    }

    buildSciFi(theme) {
        // Glowing pillars and floating platforms
        for(let i=0; i<10; i++) {
            const x = (Math.random()-0.5)*70;
            const z = (Math.random()-0.5)*70;
            this.createBox(1, 10, 1, x, 5, z, theme.accent);
        }
        // Platforms
        this.createBox(10, 0.5, 10, 0, 4, 0, theme.obstacle);
        this.createRamp(8, 0.5, 3, -7, 2, 0, 0.4, theme.accent);
    }

    buildDesert(theme) {
        // Sandstone blocks and pillars
        for(let i=0; i<20; i++) {
            const x = (Math.random()-0.5)*80;
            const z = (Math.random()-0.5)*80;
            const h = 1 + Math.random()*5;
            this.createBox(2, h, 2, x, h/2, z, theme.obstacle);
        }
        // Big Ramp
        this.createRamp(15, 0.5, 10, 20, 3, 20, -0.4, theme.accent);
    }
}

