loadMap(themeName) {
    this.clear();
    this.currentTheme = themeName;
    const theme = this.themes[themeName];

    // Background / Fog
    this.scene.background = new THREE.Color(theme.sky);
    this.scene.fog = new THREE.FogExp2(theme.sky, 0.01);

    // Floor
    this.createBox(200, 0.2, 200, 0, -0.1, 0, theme.floor);

    if (themeName === 'URBAN') {
        this.buildUrban(theme);
    } else if (themeName === 'SCIFI') {
        this.buildSciFi(theme);
    } else if (themeName === 'DESERT') {
        this.buildDesert(theme);
    }
}

constructor(scene, world) {
    this.scene = scene;
    this.world = world;
    this.meshes = [];
    this.colliders = [];
    this.currentTheme = 'URBAN';

    this.themes = {
        URBAN: { floor: 0x555555, accent: 0x888888, obstacle: 0x444444, sky: 0x8899aa },
        SCIFI: { floor: 0x000511, accent: 0x00ffff, obstacle: 0x112244, sky: 0x000205 },
        DESERT: { floor: 0xd2b48c, accent: 0xffcc00, obstacle: 0xa0522d, sky: 0xffccaa }
    };
}

createRamp(w, h, d, x, y, z, rotX, color) {
    const mesh = this.createBox(w, h, d, x, y, z, color);
    mesh.rotation.x = rotX;

    // Remove the box collider and create a rotated one
    this.world.removeCollider(this.colliders.pop());
    const desc = RAPIER.ColliderDesc.cuboid(w / 2, h / 2, d / 2)
        .setTranslation(x, y, z)
        .setRotation(new THREE.Quaternion().setFromEuler(new THREE.Euler(rotX, 0, 0)));
    const collider = this.world.createCollider(desc);
    this.colliders.push(collider);
}

buildUrban(theme) {
    for(let i=0; i<15; i++) {
        const x = (Math.random()-0.5)*80;
        const z = (Math.random()-0.5)*80;
        this.createBox(2, 1, 4, x, 0.5, z, theme.obstacle);
    }
    // Ramps (rotated on X for easier climbing)
    this.createRamp(10, 0.2, 10, 0, 1, -15, 0.3, theme.accent);
    this.createBox(10, 2, 10, 0, 1, -25, theme.obstacle);
}

