import * as THREE from 'three';
import RAPIER from '@dimforge/rapier3d-compat';

export class MapManager {
    constructor(scene, world) {
        this.scene = scene;
        this.world = world;
        this.meshes = [];
        this.colliders = [];
        this.currentTheme = 'URBAN';

        this.themes = {
            URBAN: { floor: 0x555555, accent: 0x888888, obstacle: 0x444444, sky: 0x8899aa },
            SCIFI: { floor: 0x000511, accent: 0x00ffff, obstacle: 0x112244, sky: 0x000205 },
            DESERT: { floor: 0xd2b48c, accent: 0xffcc00, obstacle: 0xa0522d, sky: 0xffccaa }
        };
    }

    clear() {
        this.meshes.forEach(m => this.scene.remove(m));
        this.colliders.forEach(c => this.world.removeCollider(c));
        this.meshes = [];
        this.colliders = [];
    }

    createBox(w, h, d, x, y, z, color, rotX = 0, rotY = 0, rotZ = 0) {
        const geo = new THREE.BoxGeometry(w, h, d);
        const mat = new THREE.MeshStandardMaterial({ color });
        const mesh = new THREE.Mesh(geo, mat);
        mesh.position.set(x, y, z);
        mesh.rotation.set(rotX, rotY, rotZ);
        mesh.castShadow = true;
        mesh.receiveShadow = true;
        this.scene.add(mesh);
        this.meshes.push(mesh);

        const desc = RAPIER.ColliderDesc.cuboid(w / 2, h / 2, d / 2)
            .setTranslation(x, y, z)
            .setRotation(new THREE.Quaternion().setFromEuler(new THREE.Euler(rotX, rotY, rotZ)));
        const collider = this.world.createCollider(desc);
        this.colliders.push(collider);
        return mesh;
    }

    loadMap(themeName) {
        this.clear();
        this.currentTheme = themeName;
        const theme = this.themes[themeName];

        // Background / Sky
        this.scene.background = new THREE.Color(theme.sky);
        this.scene.fog = new THREE.FogExp2(theme.sky, 0.015);

        // Floor
        this.createBox(200, 0.2, 200, 0, -0.1, 0, theme.floor);

        if (themeName === 'URBAN') {
            this.buildUrban(theme);
        } else if (themeName === 'SCIFI') {
            this.buildSciFi(theme);
        } else if (themeName === 'DESERT') {
            this.buildDesert(theme);
        }
    }

    buildUrban(theme) {
        for(let i=0; i<20; i++) {
            const x = (Math.random()-0.5)*100;
            const z = (Math.random()-0.5)*100;
            const h = 1 + Math.random()*3;
            this.createBox(2, h, 4, x, h/2, z, theme.obstacle);
        }
        // Central Ramp Complex
        this.createBox(10, 0.2, 10, 0, 1.5, -20, theme.accent, 0.3, 0, 0); // Ramp
        this.createBox(10, 3, 10, 0, 1.5, -30, theme.obstacle); // Platform
    }

    buildSciFi(theme) {
        for(let i=0; i<15; i++) {
            const x = (Math.random()-0.5)*100;
            const z = (Math.random()-0.5)*100;
            this.createBox(1, 15, 1, x, 7.5, z, theme.accent);
        }
        // High Platform
        this.createBox(15, 0.5, 15, 0, 5, 0, theme.obstacle);
        this.createBox(15, 0.2, 5, 0, 2.5, 10, theme.accent, -0.4, 0, 0); // Ramp up
    }

    buildDesert(theme) {
        for(let i=0; i<25; i++) {
            const x = (Math.random()-0.5)*120;
            const z = (Math.random()-0.5)*120;
            const h = 2 + Math.random()*8;
            this.createBox(3, h, 3, x, h/2, z, theme.obstacle);
        }
        // Big Sand Dune Ramp
        this.createBox(20, 0.2, 30, 30, 4, 30, theme.accent, -0.3, 0.5, 0);
    }
}

