import * as THREE from 'three';
import RAPIER from '@dimforge/rapier3d-compat';
import { MapManager } from './mapManager.js';

class Game {
    constructor() {
        this.scene = new THREE.Scene();
        this.camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        this.renderer = new THREE.WebGLRenderer({ antialias: true });
        this.renderer.setSize(window.innerWidth, window.innerHeight);
        this.renderer.shadowMap.enabled = true;
        document.body.appendChild(this.renderer.domElement);

        this.clock = new THREE.Clock();
        this.keys = {};
        this.isLocked = false;

        this.initPhysics().then(() => {
            this.mapManager = new MapManager(this.scene, this.world);
            this.initLights();
            this.initPlayer();
            this.mapManager.loadMap('URBAN');
            this.setupEvents();
            this.animate();
        });
    }

    async initPhysics() {
        await RAPIER.init();
        this.world = new RAPIER.World({ x: 0.0, y: -9.81, z: 0.0 });
    }

    initLights() {
        const ambient = new THREE.AmbientLight(0xffffff, 0.4);
        this.scene.add(ambient);

        const sun = new THREE.DirectionalLight(0xffffff, 1.2);
        sun.position.set(50, 100, 50);
        sun.castShadow = true;
        sun.shadow.camera.left = -50;
        sun.shadow.camera.right = 50;
        sun.shadow.camera.top = 50;
        sun.shadow.camera.bottom = -50;
        sun.shadow.mapSize.width = 2048;
        sun.shadow.mapSize.height = 2048;
        this.scene.add(sun);

        // Hemisphere light for better outdoor coloring
        const hemi = new THREE.HemisphereLight(0xeeeeff, 0xaa9988, 0.5);
        this.scene.add(hemi);
    }

    initPlayer() {
        // Player Physics Body (Capsule)
        const radius = 0.5;
        const height = 1.0;
        const rigidBodyDesc = RAPIER.RigidBodyDesc.kinematicPositionBased()
            .setTranslation(0, 5, 0)
            .setCanSleep(false);
        this.playerBody = this.world.createRigidBody(rigidBodyDesc);

        const colliderDesc = RAPIER.ColliderDesc.capsule(height / 2, radius);
        this.playerCollider = this.world.createCollider(colliderDesc, this.playerBody);

        this.characterController = this.world.createCharacterController(0.01);
        this.characterController.setApplyImpulsesToDynamicBodies(true);
        this.characterController.enableAutostep(0.5, 0.2, true);
        this.characterController.enableSnapToGround(0.5);

        this.playerRotation = new THREE.Euler(0, 0, 0, 'YXZ');
        this.camera.position.set(0, 0.6, 0); 
    }

    setupEvents() {
        window.addEventListener('keydown', (e) => {
            this.keys[e.code] = true;

            // Map Switching Keys
            if (e.code === 'Digit8') this.mapManager.loadMap('URBAN');
            if (e.code === 'Digit9') this.mapManager.loadMap('SCIFI');
            if (e.code === 'Digit0') this.mapManager.loadMap('DESERT');
