import * as THREE from 'three';

export const WEAPON_DATA = {
    RIFLE: { name: 'Rifle', fireRate: 0.1, damage: 20, clip: 30, maxAmmo: 90, type: 'hitscan', spread: 0.02, zoom: 0, reloadTime: 1.5 },
    SNIPER: { name: 'Sniper', fireRate: 1.5, damage: 100, clip: 5, maxAmmo: 20, type: 'hitscan', spread: 0, zoom: 15, reloadTime: 2.5 },
    DEAGLE: { name: 'Deagle', fireRate: 0.5, damage: 50, clip: 7, maxAmmo: 35, type: 'hitscan', spread: 0.01, zoom: 0, reloadTime: 1.8 },
    PISTOL: { name: 'Silenced Pistol', fireRate: 0.2, damage: 15, clip: 12, maxAmmo: 60, type: 'hitscan', spread: 0.015, zoom: 0, reloadTime: 1.2 },
    SHOTGUN: { name: 'Shotgun', fireRate: 1.0, damage: 15, clip: 6, maxAmmo: 24, type: 'hitscan', pellets: 8, spread: 0.1, zoom: 0, reloadTime: 2.0 },
    GRENADE: { name: 'Grenade Launcher', fireRate: 1.2, damage: 80, clip: 4, maxAmmo: 12, type: 'projectile', zoom: 0, reloadTime: 2.2 },
    SWORD: { name: 'Sword', fireRate: 0.5, damage: 60, type: 'melee', range: 3, zoom: 0 }
};

export class WeaponSystem {
    constructor(scene, camera) {
        this.scene = scene;
        this.camera = camera;
        this.currentWeaponKey = 'RIFLE';
        this.isZoomed = false;
        this.isReloading = false;
        this.lastFireTime = 0;

        this.ammoStates = {};
        Object.keys(WEAPON_DATA).forEach(key => {
            const data = WEAPON_DATA[key];
            if (data.clip) {
                this.ammoStates[key] = { clip: data.clip, reserve: data.maxAmmo };
            }
        });

        this.initAudio();
        this.initViewmodel();
    }

    initAudio() {
        this.listener = new THREE.AudioListener();
        this.camera.add(this.listener);
        this.audioLoader = new THREE.AudioLoader();

        // We'll use synthesizer sounds for now to avoid external dependencies
        this.shootSound = new THREE.Audio(this.listener);
        this.impactSound = new THREE.Audio(this.listener);
    }

    playShootSound() {
        // Simple procedural click/thud if audio files aren't loaded
        const oscillator = this.listener.context.createOscillator();
        const gain = this.listener.context.createGain();
        oscillator.connect(gain);
        gain.connect(this.listener.context.destination);

        oscillator.type = 'square';
        oscillator.frequency.setValueAtTime(150, this.listener.context.currentTime);
        oscillator.frequency.exponentialRampToValueAtTime(0.01, this.listener.context.currentTime + 0.1);

        gain.gain.setValueAtTime(0.1, this.listener.context.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.01, this.listener.context.currentTime + 0.1);

        oscillator.start();
        oscillator.stop(this.listener.context.currentTime + 0.1);
    }

    initViewmodel() {
        this.viewmodelGroup = new THREE.Group();
        this.camera.add(this.viewmodelGroup);

        const gunGeo = new THREE.BoxGeometry(0.1, 0.15, 0.6);
        const gunMat = new THREE.MeshStandardMaterial({ color: 0x222222 });
        this.gunMesh = new THREE.Mesh(gunGeo, gunMat);
        this.gunMesh.position.set(0.3, -0.3, -0.5);
        this.viewmodelGroup.add(this.gunMesh);

        this.originalGunPos = this.gunMesh.position.clone();
        this.originalGunRot = this.gunMesh.rotation.clone();
    }

    switchWeapon(key) {
        if (!WEAPON_DATA[key] || this.isReloading) return;
        this.currentWeaponKey = key;
        this.setZoom(false);
        this.updateHUD();
        this.gunMesh.material.color.set(key === 'SWORD' ? 0x888888 : 0x222222);
    }

    updateHUD() {
        const data = WEAPON_DATA[this.currentWeaponKey];
        const state = this.ammoStates[this.currentWeaponKey];
        document.getElementById('weapon-name').innerText = data.name;

        if (state) {
            document.getElementById('ammo').innerText = `${state.clip} / ${state.reserve}`;
            document.getElementById('reload-msg').style.display = (state.clip === 0 && state.reserve > 0) ? 'block' : 'none';
        } else {
            document.getElementById('ammo').innerText = '∞';
            document.getElementById('reload-msg').style.display = 'none';
        }
    }

    setZoom(active) {
        const data = WEAPON_DATA[this.currentWeaponKey];
        if (data.zoom > 0) {
            this.isZoomed = active;
            this.camera.fov = active ? data.zoom : 75;
            this.camera.updateProjectionMatrix();
            document.getElementById('scope').style.display = active ? 'block' : 'none';
            document.getElementById('crosshair').style.display = active ? 'none' : 'block';
            this.viewmodelGroup.visible = !active;
        }
    }

    reload() {
        const data = WEAPON_DATA[this.currentWeaponKey];
        const state = this.ammoStates[this.currentWeaponKey];
        if (!state || this.isReloading || state.clip === data.clip || state.reserve <= 0) return;

        this.isReloading = true;
        this.setZoom(false);

        // Animation: Rotate the gun
        const reloadDuration = data.reloadTime * 1000;
        const startRot = this.gunMesh.rotation.x;
        const startTime = performance.now();

        const animateReload = (now) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / reloadDuration, 1);
            this.gunMesh.rotation.x = startRot + Math.sin(progress * Math.PI) * 1.5;

            if (progress < 1) {
                requestAnimationFrame(animateReload);
            } else {
                this.isReloading = false;
                const needed = data.clip - state.clip;
                const transfer = Math.min(needed, state.reserve);
                state.clip += transfer;
                state.reserve -= transfer;
                this.updateHUD();
                this.gunMesh.rotation.x = startRot;
            }
        };
        requestAnimationFrame(animateReload);
    }

    shoot() {
        if (this.isReloading) return;
        const now = performance.now();
        const data = WEAPON_DATA[this.currentWeaponKey];
        const state = this.ammoStates[this.currentWeaponKey];

        if (now - this.lastFireTime < data.fireRate * 1000) return;
        if (state && state.clip <= 0) {
            this.updateHUD();
            return;
        }

        this.lastFireTime = now;
        if (state) state.clip--;
        this.updateHUD();
        this.playShootSound();

        // Kickback animation
        this.gunMesh.position.z += 0.15;
        setTimeout(() => this.gunMesh.position.z -= 0.15, 50);

        if (data.type === 'hitscan') {
            this.fireHitscan(data);
        } else if (data.type === 'melee') {
            this.fireMelee(data);
        }
    }

    fireHitscan(data) {
        const raycaster = new THREE.Raycaster();
        const center = new THREE.Vector2(0, 0);
        const count = data.pellets || 1;

        for(let i=0; i<count; i++) {
            raycaster.setFromCamera(center, this.camera);
            if (data.spread > 0) {
                raycaster.ray.direction.x += (Math.random() - 0.5) * data.spread;
                raycaster.ray.direction.y += (Math.random() - 0.5) * data.spread;
            }
            const intersects = raycaster.intersectObjects(this.scene.children, true);
            if (intersects.length > 0) {
                this.createImpactEffect(intersects[0].point);
            }
        }
    }

    fireMelee(data) {
        const raycaster = new THREE.Raycaster();
        raycaster.setFromCamera(new THREE.Vector2(0,0), this.camera);
        const intersects = raycaster.intersectObjects(this.scene.children, true);
        if (intersects.length > 0 && intersects[0].distance < data.range) {
            this.createImpactEffect(intersects[0].point);
        }
    }

    createImpactEffect(point) {
        const geo = new THREE.SphereGeometry(0.05, 4, 4);
        const mat = new THREE.MeshBasicMaterial({ color: 0xffff00 });
        const mesh = new THREE.Mesh(geo, mat);
        mesh.position.copy(point);
        this.scene.add(mesh);
        setTimeout(() => this.scene.remove(mesh), 200);
    }

    update(delta, time, isMoving) {
        // View Bobbing
        if (isMoving && !this.isZoomed) {
            const bobSpeed = 10;
            const bobAmount = 0.02;
            this.gunMesh.position.y = this.originalGunPos.y + Math.sin(time * bobSpeed) * bobAmount;
            this.gunMesh.position.x = this.originalGunPos.x + Math.cos(time * bobSpeed * 0.5) * bobAmount;
        } else {
            this.gunMesh.position.y = THREE.MathUtils.lerp(this.gunMesh.position.y, this.originalGunPos.y, 0.1);
            this.gunMesh.position.x = THREE.MathUtils.lerp(this.gunMesh.position.x, this.originalGunPos.x, 0.1);
        }
    }
}

