        toolbar.innerHTML = '';
        Object.keys(WEAPON_DATA).forEach((key, index) => {
            const slot = document.createElement('div');
            slot.className = `weapon-slot ${key === this.currentWeaponKey ? 'active' : ''}`;
            slot.id = `slot-${key}`;
            slot.innerHTML = index + 1;
            toolbar.appendChild(slot);
        });
