        for(let i=0; i<10; i++) {
            const p = point.clone().add(new THREE.Vector3((Math.random()-0.5)*2, (Math.random()-0.5)*2, (Math.random()-0.5)*2));
            this.createImpactEffect(p, 0xffaa00, 0.3);
